PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?dynasty ?dynastyLabel (YEAR(?end) - YEAR(?start) AS ?duration)
WHERE {
  ?dynasty wdt:P31 wd:Q164950;
            wdt:P1346 wd:Q2261;
            wdt:P580 ?start;
            wdt:P582 ?end;
            rdfs:label ?dynastyLabel.
  FILTER(LANG(?dynastyLabel) = "en")
}
ORDER BY ?duration

