PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?dynasty ?dynastyLabel (MIN(?start) AS ?firstStart) (MAX(?end) AS ?lastEnd) ((YEAR(MAX(?end)) - YEAR(MIN(?start))) AS ?durationYears)
WHERE {
  ?emperor wdt:P39 wd:Q1169656;
             wdt:P17 wd:Q2261;
             wdt:P177 ?dynasty;
             wdt:P580 ?start;
             wdt:P582 ?end.
  ?dynasty wdt:P31 wd:Q164950;
           rdfs:label ?dynastyLabel.
  FILTER(LANG(?dynastyLabel) = "en")
}
GROUP BY ?dynasty ?dynastyLabel
ORDER BY ?durationYears

PREFIX wd: <http://www.wikidata.org/entity/>
